'use client';

import { useState, useEffect } from 'react';

const items = [
  {
    title: "Tickets Diary",
    description: "我自己研发的应用和网页",
    images: [
      { src: `${process.env.NEXT_PUBLIC_BASE_PATH || ''}/tickets-diary.png`, alt: "Tickets Diary 1" },
      { src: "https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?w=600&auto=format&fit=crop&q=60", alt: "Tickets Diary 2" },
    ],
  },
  {
    title: "Fortune Trinkets",
    description: "我自己研发的应用和网页",
    images: [
      { src: "https://images.unsplash.com/photo-1515562141207-7a88fb7ce338?w=600&auto=format&fit=crop&q=60", alt: "Fortune Trinkets 1" },
      { src: "https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=600&auto=format&fit=crop&q=60", alt: "Fortune Trinkets 2" },
    ],
  },
  {
    title: "Coming Soon",
    description: "敬请期待",
    images: [
      { src: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?w=600&auto=format&fit=crop&q=60", alt: "Coming Soon 1" },
      { src: "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=600&auto=format&fit=crop&q=60", alt: "Coming Soon 2" },
    ],
  },
];

export function ProjectShowcase() {
  const [activeIndex, setActiveIndex] = useState(0);
  const [imgIndex, setImgIndex] = useState(0);

  // auto-advance image within active item
  useEffect(() => {
    setImgIndex(0);
    const t = setInterval(() => {
      setImgIndex(prev => (prev + 1) % items[activeIndex].images.length);
    }, 2000);
    return () => clearInterval(t);
  }, [activeIndex]);

  // auto-advance through items
  useEffect(() => {
    const t = setInterval(() => {
      setActiveIndex(prev => (prev + 1) % items.length);
    }, 4000);
    return () => clearInterval(t);
  }, []);

  return (
    <div
      className="w-full max-w-5xl mx-auto px-8"
      style={{
        display: 'flex',
        flexDirection: 'row',
        alignItems: 'center',
        gap: '80px',
      }}
    >
      {/* Left: label + item list */}
      <div style={{ flex: '0 0 auto', display: 'flex', flexDirection: 'column' }}>
        <h3
          className="text-sm font-black uppercase"
          style={{
            fontFamily: "'Adobe Song Std', 'AdobeSongStd', serif",
            color: '#7a7060',
            letterSpacing: '0.12em',
            margin: '0 0 28px',
          }}
        >
          Demo
        </h3>

        {items.map((item, i) => (
          <div
            key={i}
            onMouseEnter={() => setActiveIndex(i)}
            style={{
              cursor: 'pointer',
              paddingBottom: '24px',
              marginBottom: i < items.length - 1 ? '8px' : '0',
              borderBottom: i < items.length - 1 ? '1px solid rgba(42,32,16,0.08)' : 'none',
            }}
          >
            <h2
              style={{
                fontFamily: "'Adobe Song Std', 'AdobeSongStd', serif",
                fontSize: '36px',
                fontWeight: 900,
                color: activeIndex === i ? '#2a2010' : '#7a7060',
                margin: 0,
                transition: 'color 0.4s ease',
                lineHeight: 1.1,
              }}
            >
              {item.title}
            </h2>
            <div
              style={{
                maxHeight: activeIndex === i ? '32px' : '0',
                overflow: 'hidden',
                transition: 'max-height 0.4s ease',
              }}
            >
              <p
                style={{
                  fontFamily: "Georgia, 'Songti SC', STSong, serif",
                  fontSize: '13px',
                  color: '#2a2010',
                  margin: '6px 0 0',
                  letterSpacing: '0.06em',
                }}
              >
                {item.description}
              </p>
            </div>
          </div>
        ))}
      </div>

      {/* Right: auto-rotating image */}
      <div style={{ flex: '1 1 0', position: 'relative' }}>

        {/* Tickets Diary: in-flow, auto height, transparent */}
        <div
          style={{
            opacity: activeIndex === 0 ? 1 : 0,
            transition: 'opacity 0.9s ease',
            pointerEvents: activeIndex === 0 ? 'auto' : 'none',
            width: '600px',
          }}
        >
          {items[0].images.map((img, j) => (
            <img
              key={`0-${j}`}
              src={img.src}
              alt={img.alt}
              style={{
                display: 'block',
                width: '600px',
                height: 'auto',
                objectFit: 'contain',
                opacity: imgIndex === j ? 1 : 0,
                transition: 'opacity 0.9s ease',
                position: j > 0 ? 'absolute' : 'relative',
                top: j > 0 ? 0 : undefined,
                left: j > 0 ? 0 : undefined,
              }}
            />
          ))}
        </div>

        {/* Fortune Trinkets & Coming Soon: absolute, fixed height, with style */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '520px',
            maxWidth: '520px',
            borderRadius: '16px',
            overflow: 'hidden',
            boxShadow: '0 8px 40px rgba(0,0,0,0.12)',
            opacity: activeIndex === 0 ? 0 : 1,
            transition: 'opacity 0.9s ease',
            pointerEvents: activeIndex === 0 ? 'none' : 'auto',
          }}
        >
          {items.slice(1).map((item, i) =>
            item.images.map((img, j) => (
              <img
                key={`${i + 1}-${j}`}
                src={img.src}
                alt={img.alt}
                style={{
                  position: 'absolute',
                  inset: 0,
                  width: '100%',
                  height: '100%',
                  objectFit: 'contain',
                  opacity: activeIndex === i + 1 && imgIndex === j ? 1 : 0,
                  transition: 'opacity 0.9s ease',
                }}
              />
            ))
          )}
        </div>

      </div>
    </div>
  );
}
